const accessToken = 'AAAAAAAAAAAAAAAAAAAAAEVj7QEAAAAAK7smDPQu03MV7ybVGV%2BM4HKy7nU%3DB9VdGySGheUaf0mm8iCP5UJuqLCwvNbfbFwdC3mZw5YjImM2Kc';
const tokenSecret = '7LaVfnN7COvq4NevfYAoHjt3O'; // Access Token Secret

// 2. TWEET CONTENT
const tweetText = "Hello from my n8n workflow! 🚀";

// 3. OAUTH PARAMETERS
const method = 'POST';
const url = 'https://api.twitter.com/2/tweets';
const nonce = crypto.randomBytes(16).toString('hex');
const timestamp = Math.floor(Date.now() / 1000).toString();

const oauthParams = {
    oauth_consumer_key: consumerKey,
    oauth_nonce: nonce,
    oauth_signature_method: 'HMAC-SHA1',
    oauth_timestamp: timestamp,
    oauth_token: accessToken,
    oauth_version: '1.0'
};

// 4. GENERATE SIGNATURE
const parameterString = Object.keys(oauthParams).sort().map(key => 
    `${encodeURIComponent(key)}=${encodeURIComponent(oauthParams[key])}`
).join('&');

const signatureBaseString = `${method}&${encodeURIComponent(url)}&${encodeURIComponent(parameterString)}`;
const signingKey = `${encodeURIComponent(consumerSecret)}&${encodeURIComponent(tokenSecret)}`;

const signature = crypto.createHmac('sha1', signingKey)
    .update(signatureBaseString)
    .digest('base64');

oauthParams.oauth_signature = signature;

// 5. BUILD AUTHORIZATION HEADER
const authHeader = 'OAuth ' + Object.keys(oauthParams).sort().map(key => 
    `${encodeURIComponent(key)}="${encodeURIComponent(oauthParams[key])}"`
).join(', ');

// 6. OUTPUT DATA FOR HTTP REQUEST NODE
return {
    headers: {
        'Authorization': authHeader,
        'Content-Type': 'application/json'
    },
    body: {
        text: tweetText
    }
